import { escapeHtml } from './sanitize.js'

/**
 * Convert minimal inline markdown (**bold**, *italic*) to HTML.
 *
 * Processing order: escape HTML first, then bold, then italic.
 * This ensures only <strong> and <em> tags we produce appear in the output.
 * IMPORTANT: Never reverse this order -- escaping must precede markdown
 * conversion to prevent HTML injection via v-html.
 */
export function renderInlineMarkdown(text) {
  if (typeof text !== 'string') return ''
  if (!text) return ''

  let result = escapeHtml(text)

  // Bold-italic: ***text*** must be handled before ** and * to avoid
  // the bold pass consuming only two of the three leading asterisks.
  result = result.replace(/\*\*\*(.+?)\*\*\*/g, '<strong><em>$1</em></strong>')

  // Bold: **text** (non-greedy, single-line only)
  result = result.replace(/\*\*(.+?)\*\*/g, '<strong>$1</strong>')

  // Italic: *text* -- negative lookbehind/lookahead for * prevents
  // matching inside bold delimiters or consuming *** patterns incorrectly.
  result = result.replace(/(?<!\*)\*(?!\*)(.+?)(?<!\*)\*(?!\*)/g, '<em>$1</em>')

  return result
}

/** Basic URL sanitizer to avoid javascript: and other dangerous schemes. */
export function sanitizeUrl(input) {
  if (typeof input !== 'string' || !input.trim()) return '#'
  const url = input.trim()
  // Allow relative URLs
  if (url.startsWith('/') || url.startsWith('./') || url.startsWith('../')) return url
  try {
    const u = new URL(url)
    const allowed = ['http:', 'https:'] // Reject data:, blob:, javascript:, etc.
    if (!allowed.includes(u.protocol)) return '#'
    return u.toString()
  } catch {
    return '#'
  }
}

/** Sanitize image/video src: allow only http(s) or relative. */
export function sanitizeSrc(input) {
  if (typeof input !== 'string' || !input.trim()) return null
  const url = input.trim()
  if (url.startsWith('/') || url.startsWith('./') || url.startsWith('../')) return url
  try {
    const u = new URL(url)
    const allowed = ['http:', 'https:']
    if (!allowed.includes(u.protocol)) return null
    return u.toString()
  } catch {
    return null
  }
}

/** Escape HTML special characters. */
export function escapeHtml(input) {
  if (typeof input !== 'string') return ''
  return input
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
}

/** Escape all HTML then permit <br> tags back (simple allowlist). */
export function allowBrText(input) {
  if (typeof input !== 'string') return ''
  const escaped = escapeHtml(input)
  return escaped.replace(/&lt;br\s*\/?&gt;/gi, '<br>')
}

/**
 * Validates a URL slug parameter to prevent path traversal attacks.
 * Only allows alphanumeric characters, hyphens, and underscores.
 *
 * @param {string} slug - The slug to validate
 * @returns {boolean} - True if valid, false otherwise
 */
export function isValidSlug(slug) {
  if (!slug || typeof slug !== 'string') return false
  // Only allow alphanumeric, hyphens, and underscores (no slashes, dots, etc.)
  // Max length of 200 to prevent excessively long inputs
  return /^[a-zA-Z0-9_-]{1,200}$/.test(slug)
}

